package inequivalent;

import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertThrows;

class ClonePair2Method1Test {

    private static final double DELTA = 1.0e-9;

    private final ClonePair2 subject = new ClonePair2();

    @Test
    void method1ReturnsZeroForIdenticalArrays() {
        // Generated by Codex (gpt-5.4).
        Integer[] curr = {1, 2, 3};
        Integer[] orig = {1, 2, 3};

        assertEquals(0.0, subject.method1(curr, orig, 2, 2), DELTA);
    }

    @Test
    void method1ReturnsNormalizedAbsoluteDifference() {
        // Generated by Codex (gpt-5.4).
        Integer[] curr = {3, -1, 10};
        Integer[] orig = {1, 2, 4};

        assertEquals(2.75, subject.method1(curr, orig, 2, 2), DELTA);
    }

    @Test
    void method1ReturnsZeroForEmptyArrays() {
        // Generated by Codex (gpt-5.4).
        Integer[] curr = {};
        Integer[] orig = {};

        assertEquals(0.0, subject.method1(curr, orig, 3, 4), DELTA);
    }

    @Test
    void method1ReturnsInfinityWhenDivisorIsZeroAndDifferenceExists() {
        // Generated by Codex (gpt-5.4).
        Integer[] curr = {5};
        Integer[] orig = {1};

        assertEquals(Double.POSITIVE_INFINITY, subject.method1(curr, orig, 0, 3), DELTA);
    }

    @Test
    void method1ThrowsNullPointerExceptionWhenCurrentArrayIsNull() {
        // Generated by Codex (gpt-5.4).
        Integer[] orig = {1};

        assertThrows(NullPointerException.class, () -> subject.method1(null, orig, 1, 1));
    }
}
